import json
from collections import Counter
from flask import Flask, request, jsonify

app = Flask(__name__)

# Define a dictionary to store the image labels
image_labels = {}

@app.route('/label', methods=['POST'])
def label():
    # Get the image ID and label from the request body
    image_id = request.json['image_id']
    label = request.json['label']
    
    # Add the label to the dictionary for the corresponding image ID
    if image_id not in image_labels:
        image_labels[image_id] = []
    image_labels[image_id].append(label)
    
    return jsonify({'status': 'success'})

@app.route('/aggregate', methods=['GET'])
def aggregate():
    # Get the list of image IDs from the request query string
    image_ids = request.args.getlist('image_id')
    
    # Initialize a dictionary to store the aggregated labels
    aggregated_labels = {}
    
    # Iterate over each image ID and calculate the majority vote for its label
    for image_id in image_ids:
        if image_id not in image_labels:
            continue
        labels = image_labels[image_id]
        aggregated_label = Counter(labels).most_common()[0][0]
        aggregated_labels[image_id] = aggregated_label
    
    return jsonify({'aggregated_labels': aggregated_labels})

